const hoy = new Date();
const mesActual = hoy.getMonth();

// Sumamos 7 días a la fecha actual
const proximoViernes = new Date(hoy);
proximoViernes.setDate(hoy.getDate() + 7);

// Si el mes del próximo viernes es distinto al actual, 
// significa que este es el último viernes del mes.
const esUltimoViernes = proximoViernes.getMonth() !== mesActual;

return {
  esUltimo: esUltimoViernes,
  mesNombre: hoy.toLocaleString('es-ES', { month: 'long' })
};
